41	
42	  // ---------- Components and block-of-3 ----------
43	  it("2 runes → 50 G base premium (no block); total 50 + 5 surcharge + 5 fee = 60 G", () => {
44	    const result = runScenario({
45	      customer: { yearsWithMHPCO: 0 },
46	      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }] }],
47	    });
48	    expect(result).toEqual({ results: [{ premium: 60 }] });
