51	    const result = runScenario({
52	      customer: { yearsWithMHPCO: 0 },
53	      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }] }],
54	    });
55	    expect(result).toEqual({ results: [{ premium: 71 }] });
