57	  it.todo("4 runes → 100 G base premium (no block — block requires exactly 3)");
58	  it.todo("7 runes → 175 G base premium (no block — block requires exactly 3 alike)");
59	  it.todo("2 runes + 1 moonstone → 75 G base premium (no block: different types)");
60	  it.todo("3 runes + 3 moonstones → 120 G base premium (two separate blocks)");
61	
62	  // ---------- Item-level modifiers ----------
63	  it.todo("cursed sword (newcomer, first contract) → 100 + 50 curse + 15 first insurance + 5 fee = 170 G");
64	  it.todo("sword with exactly enchantment 5 → high-enchantment surcharge applies");
65	  it.todo("sword with enchantment 4 → no high-enchantment surcharge");
66	  it.todo("cursed sword with enchantment 5 → both curse and high-enchantment surcharges apply");
67	
68	  // ---------- Policy-wide modifiers ----------
69	  it.todo("customer with exactly 2 years with MHPCO → loyalty discount applies");
70	  it.todo("customer with less than 2 years → no loyalty discount");
71	  it.todo("second quote in scenario → follow-up contract discount applies");
72	
73	  // ---------- Modifier scope on multi-item policies ----------
74	  it.todo("cursed sword + plain amulet → 100 + 60 + 50 curse = 210 G + 10 first ins on sword + 6 first ins on amulet + 5 fee");
75	  it.todo("first insurance surcharge applies per item, not per policy");
76	
77	  // ---------- Rounding in MHPCO's favor ----------
78	  it.todo("premium calculation yielding 197.5 G → rounded up to 198 G");
79	  it.todo("payout calculation yielding 350.5 G → rounded down to 350 G");
80	
81	  // ---------- Integration premium examples ----------
82	  it.todo("newcomer with cursed sword (steel, enchantment 3) → premium 165 G");
83	  it.todo("long-standing (3y) customer's second contract: cursed sword enchantment 7 → premium 160 G");
84	
85	  // ---------- Claims: simple cases ----------
86	  it.todo("regular sword (steel, enchantment 3), damage 500 → payout 400 G (full minus deductible)");
87	  it.todo("damage to a rune (insurance value 250), damage 200 → payout 100 G (full minus deductible)");
88	
89	  // ---------- Claims: special clauses ----------
90	  it.todo("dragon-material sword enchantment 5, damage 800 → payout 700 G (dragon: full, minus deductible)");
