93	  it.todo("dragon-material sword enchantment 8, damage 1000 → payout 400 G (high-enchantment then deductible)");
94	
95	  // ---------- Claims: deductible per damage event ----------
96	  it.todo("dragon attack damages sword (500) and amulet (300) → payout 600 G (deductible applies per item)");
97	
98	  // ---------- Claims: cap ----------
99	  it.todo("cursed sword (insurance value 1000) → cap 2000 G (based on unmodified insurance value)");
100	  it.todo("sword + amulet → insurance sum 1600 G, cap 3200 G");
101	  it.todo("sword + 3 runes (block) → insurance sum 1750 G (block does not affect insurance sum)");
102	  it.todo("sword cap 2000 G, two successive claims of 1500: first payout 1400, cap remaining 600; second payout 600, cap remaining 0");
103	
104	  // ---------- Claims: multiple items of same type ----------
105	  it.todo("policy of two swords → insurance sum 2000 G, cap 4000 G");
106	  it.todo("two swords insured, two sword damage entries → each treated as separate damage with own deductible");
107	  it.todo("damages has more entries of a type than insured → CLI exits non-zero");
108	
109	  // ---------- Edge cases / errors ----------
110	  it.todo("quote with unknown item type → CLI exits non-zero, error to stderr, no results on stdout");
111	  it.todo("claim references damage entry whose item is not part of policy → CLI exits non-zero");
112	  it.todo("claim with damage entry of unknown item type → CLI exits non-zero");
113	  it.todo("claim with negative damage amount → CLI exits non-zero");
114	
115	  // ---------- CLI / multi-step scenario ----------
116	  it.todo("scenario with quote then claim returns results array of matching length and order");
117	  it.todo("claim's policy field references quote step by zero-based index");
118	});
