1	type Item = { type: string };
2	type Step = { op: "quote"; items: Item[] };
3	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
4	
5	const PROCESSING_FEE = 5;
6	const FIRST_INSURANCE_RATE = 0.1;
7	const BASE_PREMIUMS: Record<string, number> = {
8	  sword: 100,
9	  amulet: 60,
10	  staff: 80,
11	  potion: 40,
12	  rune: 25,
13	};
14	
15	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
16	const BLOCK_SIZE = 3;
17	const BLOCK_BASE_PREMIUM = 60;
18	
19	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
20	
21	const itemBasePremium = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;
22	
23	const componentGroupBasePremium = (items: Item[]): number =>
24	  items.length === BLOCK_SIZE ? BLOCK_BASE_PREMIUM : items.length * itemBasePremium(items[0]);
25	
26	const itemsBasePremium = (items: Item[]): number => {
27	  const components = items.filter(isComponent);
28	  const mainItems = items.filter((item) => !isComponent(item));
29	  const componentsByType = new Map<string, Item[]>();
30	  for (const c of components) {
31	    const group = componentsByType.get(c.type) ?? [];
32	    group.push(c);
33	    componentsByType.set(c.type, group);
34	  }
35	  const mainBase = mainItems.reduce((total, item) => total + itemBasePremium(item), 0);
36	  const componentBase = [...componentsByType.values()].reduce(
37	    (total, group) => total + componentGroupBasePremium(group),
38	    0,
39	  );
40	  return mainBase + componentBase;
41	};
42	
43	const quotePremium = (items: Item[]): number => {
44	  const base = itemsBasePremium(items);
45	  const firstInsuranceSurcharge = base * FIRST_INSURANCE_RATE;
46	  return Math.ceil(base + firstInsuranceSurcharge + PROCESSING_FEE);
47	};
48	
49	export const runScenario = (scenario: Scenario): { results: Array<{ premium: number }> } => ({
50	  results: scenario.steps.map((step) => ({ premium: quotePremium(step.items) })),
51	});
