const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);

const itemBasePremium = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;

const componentGroupBasePremium = (items: Item[]): number =>
  items.length === BLOCK_SIZE ? BLOCK_BASE_PREMIUM : items.length * itemBasePremium(items[0]);

const itemsBasePremium = (items: Item[]): number => {
  const components = items.filter(isComponent);
  const mainItems = items.filter((item) => !isComponent(item));
  const componentsByType = new Map<string, Item[]>();
  for (const c of components) {
    const group = componentsByType.get(c.type) ?? [];
    group.push(c);
    componentsByType.set(c.type, group);
  }
  const mainBase = mainItems.reduce((total, item) => total + itemBasePremium(item), 0);
  const componentBase = [...componentsByType.values()].reduce(
    (total, group) => total + componentGroupBasePremium(group),
    0,
  );
  return mainBase + componentBase;
};

